// UPDATE account
//   SET balance_cents = ?, version = ?   -- new version = old + 1
// WHERE id = ? AND version = ?            -- old version
//
// If 0 rows affected -> StaleStateException -> OptimisticLockException

// Naive CAS on a value is vulnerable to ABA:
AtomicReference<Node> top = ...;
Node oldTop = top.get();           // observe A
// ... another thread pops A, pushes B, pushes A again ...
top.compareAndSet(oldTop, oldTop.next); // succeeds! but next is stale

// Fix: pair the value with a monotonically increasing stamp.
AtomicStampedReference<Node> stampedTop = ...;
