public <T> T withRetry(int maxAttempts, Supplier<T> action) {
    long baseDelayMs = 10;
    for (int attempt = 1; ; attempt++) {
        try {
            return action.get(); // runs in its own transaction
        } catch (ObjectOptimisticLockingFailureException ex) {
            if (attempt >= maxAttempts) {
                throw new ConflictExhaustedException(attempt, ex);
            }
            long jitter = ThreadLocalRandom.current().nextLong(baseDelayMs);
            long delay = (baseDelayMs << Math.min(attempt, 6)) + jitter;
            sleepQuietly(delay); // exponential backoff with jitter
        }
    }
}

@Put(':id')
async update(
  @Param('id') id: string,
  @Headers('if-match') ifMatch: string,
  @Body() dto: UpdateDto,
  @Res() res: Response,
) {
  if (!ifMatch) {
    return res.status(428).send('If-Match header required'); // Precondition Required
  }
  const current = await this.repo.findVersion(id);
  if (`"${current.version}"` !== ifMatch) {
    return res.status(412).send('Precondition Failed'); // stale client
  }
  const next = await this.repo.conditionalUpdate(id, current.version, dto);
  if (!next) {
    return res.status(412).send('Precondition Failed'); // raced between check and write
  }
  res.setHeader('ETag', `"${next.version}"`);
  return res.status(200).json(next);
}

