public class TransferService {

    private final JdbcTemplate jdbc;
    private final TransactionTemplate tx;
    private static final int MAX_ATTEMPTS = 5;

    public TransferService(JdbcTemplate jdbc, PlatformTransactionManager txm) {
        this.jdbc = jdbc;
        this.tx = new TransactionTemplate(txm);
        this.tx.setPropagationBehavior(TransactionDefinition.PROPAGATION_REQUIRES_NEW);
    }

    public void transfer(long fromId, long toId, long amountCents) {
        for (int attempt = 1; ; attempt++) {
            try {
                tx.executeWithoutResult(status -> doTransfer(fromId, toId, amountCents));
                return; // committed, no conflict
            } catch (OptimisticConflictException ex) {
                if (attempt >= MAX_ATTEMPTS) {
                    throw new ConflictExhaustedException(fromId, toId, attempt);
                }
                backoff(attempt);
            }
        }
    }

    private void doTransfer(long fromId, long toId, long amountCents) {
        var from = readAccount(fromId);
        var to = readAccount(toId);
        if (from.balanceCents() < amountCents) {
            throw new InsufficientFundsException(fromId);
        }
        applyVersioned(fromId, from.version(), from.balanceCents() - amountCents);
        applyVersioned(toId, to.version(), to.balanceCents() + amountCents);
    }

    private void applyVersioned(long id, long expectedVersion, long newBalance) {
        int rows = jdbc.update(
            "UPDATE account SET balance_cents = ?, version = version + 1 " +
            "WHERE id = ? AND version = ?",
            newBalance, id, expectedVersion);
        if (rows == 0) {
            throw new OptimisticConflictException(id, expectedVersion);
        }
    }

    private Account readAccount(long id) {
        return jdbc.queryForObject(
            "SELECT id, balance_cents, version FROM account WHERE id = ?",
            (rs, n) -> new Account(rs.getLong("id"), rs.getLong("balance_cents"), rs.getLong("version")),
            id);
    }

    private void backoff(int attempt) {
        long base = 10L << Math.min(attempt, 6);
        long jitter = ThreadLocalRandom.current().nextLong(base);
        try { Thread.sleep(base + jitter); }
        catch (InterruptedException e) { Thread.currentThread().interrupt(); }
    }

    record Account(long id, long balanceCents, long version) { }
}

import { Controller, Get, Put, Param, Headers, Body, Res } from '@nestjs/common';
import { Response } from 'express';

interface Account { id: string; balanceCents: number; version: number; }

@Controller('accounts')
export class AccountController {
  constructor(private readonly repo: AccountRepo) {}

  @Get(':id')
  async read(@Param('id') id: string, @Res() res: Response) {
    const acct = await this.repo.find(id);
    if (!acct) return res.status(404).send('Not Found');
    res.setHeader('ETag', `"${acct.version}"`);
    return res.status(200).json(acct);
  }

  @Put(':id')
  async update(
    @Param('id') id: string,
    @Headers('if-match') ifMatch: string | undefined,
    @Body() body: { balanceCents: number },
    @Res() res: Response,
  ) {
    if (!ifMatch) {
      return res.status(428).send('If-Match header required');
    }
    const current = await this.repo.find(id);
    if (!current) return res.status(404).send('Not Found');

    const expected = `"${current.version}"`;
    if (ifMatch !== expected) {
      return res.status(412).send('Precondition Failed');
    }

    // Authoritative compare-and-set at the database layer.
    const updated = await this.repo.conditionalUpdate(
      id,
      current.version,
      body.balanceCents,
    );
    if (!updated) {
      // Two requests passed the in-memory check and raced; loser gets 412.
      return res.status(412).send('Precondition Failed');
    }
    res.setHeader('ETag', `"${updated.version}"`);
    return res.status(200).json(updated);
  }
}

class AccountRepo {
  constructor(private readonly db: Db) {}

  find(id: string): Promise<Account | null> {
    return this.db.queryOne<Account>(
      'SELECT id, balance_cents AS "balanceCents", version FROM account WHERE id = $1',
      [id],
    );
  }

  async conditionalUpdate(
    id: string,
    expectedVersion: number,
    balanceCents: number,
  ): Promise<Account | null> {
    const rows = await this.db.query<Account>(
      `UPDATE account
          SET balance_cents = $1, version = version + 1
        WHERE id = $2 AND version = $3
      RETURNING id, balance_cents AS "balanceCents", version`,
      [balanceCents, id, expectedVersion],
    );
    return rows.length === 1 ? rows[0] : null;
  }
}
